com.mirth.connect.plugins.javascriptstep.script:
logger.info("HTTP request validation started.");
///////////////////////////////////////////////////////////////////////////////////////////


/********************************************
    1️⃣ FETCH JDBC SECRET (JSON secret)
********************************************/

try {

//var jdbcSecretName = LookupHelper.get("Config", "SM_KEY_RDS_SECRETS", ttlHours);
//    var jdbcSecretString = fetchSecret(jdbcSecretName);
//    var jdbcSecret = JSON.parse(jdbcSecretString);

	var username = LookupHelper.get("Config-sensitive", "MC_JDBC_USERNAME");
	var password = LookupHelper.get("Config-sensitive", "MC_JDBC_PASSWORD");

	channelMap.put("JDBC_USERNAME", username);
	channelMap.put("JDBC_PASSWORD", password);

	 logger.info("JDBC_USERNAME loaded: " + username);

     globalMap.put("JDBC_USERNAME", username);
     globalMap.put("JDBC_PASSWORD", password);

    logger.info(" JDBC credentials loaded into channelMap");

} catch (e) {
    logger.error(" Error processing JDBC secret: " + e.message);
}

/********************************************
    2️⃣ FETCH DATA LEDGER API KEY (Plain text)
********************************************/

try {
    var dataLedgerKey = LookupHelper.get("Config-sensitive", "TECHBD_NYEC_DATALEDGER_API_KEY");

     channelMap.put("TECHBD_NYEC_DATALEDGER_API_KEY", dataLedgerKey);
     globalMap.put("TECHBD_NYEC_DATALEDGER_API_KEY", dataLedgerKey);

      logger.info(" DataLedger API Key loaded into channelMap");

} catch (e) {
    logger.error(" Error processing DataLedger API Key secret: " + e.message);
}
/////////////////////////////////////////////////////////////////////////
/********************************************
    3️⃣ FETCH FHIR BUNDLE SUBMISSION API URL (Plain text)
********************************************/
try {
    var fhirChannelUrl = LookupHelper.get("Config", "MC_FHIR_BUNDLE_SUBMISSION_API_URL");

    if (!fhirChannelUrl || fhirChannelUrl.trim() === "") {
        throw "FHIR Channel URL retrieved from Lookup Manager is empty.";
    }
    channelMap.put("FHIR_CHANNEL_URL", fhirChannelUrl);
    globalMap.put("fhirChannelUrl", fhirChannelUrl);

     logger.info("FHIR API URL loaded successfully from Lookup Manager: " + fhirChannelUrl);

} catch (e) {
    logger.error(" Error fetching FHIR CHANNEL URL: " + e);
    setErrorResponse(500, "Failed to load FHIR CHANNEL URL");
    throw e;
}

/********************************************
    6️⃣ FETCH JDBC URL (Plain text)
********************************************/
try {
    var jdbcUrl = LookupHelper.get("Config-sensitive", "MC_JDBC_URL");

    if (!jdbcUrl || jdbcUrl.trim() === "") {
        throw " MC_JDBC_URL retrieved from Lookup Manager is empty.";
    }
    jdbcUrl = jdbcUrl.trim(); // IMPORTANT: remove trailing spaces
     globalMap.put("jdbcUrl", jdbcUrl);

     logger.info("JDBC URL loaded successfully from Lookup Manager: " + jdbcUrl);

} catch (e) {
    logger.error(" Error fetching JDBC URL: " + e);
    setErrorResponse(500, "Failed to load JDBC URL");
    throw e;
}





/********************************************
    5️⃣ FETCH DEFAULT DATALAKE API URL (Plain text)
********************************************/
try {
    var datalakeApiUrl = "";

    var rawHeader = $('headers').getHeader('X-TechBD-DataLake-API-URL');
    var incomingHeader = rawHeader == null ? "" : String(rawHeader).trim();

    var urlPattern = /^https?:\/\/[^\s]+$/i;

    if (incomingHeader !== "") { //if  incomingHeader not blank 

        if (!urlPattern.test(incomingHeader)) {
            logger.error("Invalid DataLake API URL in header: " + incomingHeader);
            datalakeApiUrl = incomingHeader;
        } else {
            datalakeApiUrl = incomingHeader;
            logger.info("Datalake API URL loaded from request header: " + datalakeApiUrl);
        }
    } else { // if incomingHeader is blak

        datalakeApiUrl = LookupHelper.get(
            "Config",
            "TECHBD_DEFAULT_DATALAKE_API_URL"
        );

        if (!datalakeApiUrl || datalakeApiUrl.trim() === "") {
            throw "DataLake API URL retrieved from Lookup Manager is empty.";
        }

        datalakeApiUrl = datalakeApiUrl.trim();
        logger.info("Header blank → using default DataLake API URL: " + datalakeApiUrl);
    }

    channelMap.put("DATALAKE_API_URL", datalakeApiUrl);
    globalMap.put("datalakeApiUrl", datalakeApiUrl);

} catch (e) {
    logger.error("Error fetching Datalake API URL: " + e);
    setErrorResponse(500, "Failed to load Datalake API URL");
    throw e;
}

/********************************************
    6️⃣ FETCH DATA LAKE API KEY (Plain text)
********************************************/

try {
    var dataLakeApiKey = LookupHelper.get("Config-sensitive", "TECHBD_NYEC_DATALAKE_API_KEY");

    channelMap.put("DATA_LAKE_API_KEY", dataLakeApiKey);
    logger.info(" DataLake API Key loaded into channelMap");

} catch (e) {
    logger.error(" Error processing DataLake API Key secret: " + e.message);
}


/********************************************
    7️⃣ FETCH FHIR BUNDLE SUBMISSION API URL (Plain text)
********************************************/
try {
    var fhirApiUrl = LookupHelper.get("Config", "BL_FHIR_BUNDLE_VALIDATION_API_URL");

    if (!fhirApiUrl || fhirApiUrl.trim() === "") {
        throw " BL FHIR Bundle Validation API URL retrieved from Lookup Manager is empty.";
    }
	fhirApiUrl = fhirApiUrl + "/Bundle/$validate";
    channelMap.put("FHIR_API_URL", fhirApiUrl);
    globalMap.put("fhirBundleSubmissionApiUrl", fhirApiUrl);
    logger.info("BL FHIR Bundle Validation API URL loaded successfully from Lookup Manager: " + fhirApiUrl);

} catch (e) {
    logger.error(" Error fetching FHIR API URL: " + e);
    setErrorResponse(500, "Failed to load FHIR API URL");
    throw e;
}


/********************************************
    8️⃣ FETCH DATA LEDGER API URL (Plain text)
********************************************/

try {
    var dataLedgerApiUrl = LookupHelper.get("Config", "DATA_LEDGER_API_URL");

     channelMap.put("DATA_LEDGER_API_URL", dataLedgerApiUrl);
     globalMap.put("DATA_LEDGER_API_URL", dataLedgerApiUrl);

     logger.info(" DataLedger API URL loaded into channelMap" + dataLedgerApiUrl);

} catch (e) {
    logger.error(" Error processing DataLedger API URL  secret: " + e.message);
}


/********************************************
    9️⃣ FETCH DATA LEDGER  DATA_LEDGER_TRACKING (Plain text)
********************************************/

try {
    var dataLedgerTracking = LookupHelper.get("Config", "DATA_LEDGER_TRACKING");

    channelMap.put("DATA_LEDGER_TRACKING", dataLedgerTracking);
    globalMap.put("DATA_LEDGER_TRACKING", dataLedgerTracking);

    logger.info(" DataLedger Tracking loaded into channelMap"+ dataLedgerTracking);

} catch (e) {
    logger.error(" Error processing DataLedger Tracking secret: " + e.message);
}


/********************************************
    9️⃣ FETCH DATA LEDGER  DATA_LEDGER_DIAGNOSTICS (Plain text)
********************************************/

try {
    var dataLedgerDiagnostics = LookupHelper.get("Config", "DATA_LEDGER_DIAGNOSTICS");

    channelMap.put("DATA_LEDGER_DIAGNOSTICS", dataLedgerDiagnostics);
    globalMap.put("DATA_LEDGER_DIAGNOSTICS", dataLedgerDiagnostics);

    logger.info(" DataLedger diagnostics loaded into channelMap"+ dataLedgerDiagnostics);

} catch (e) {
    logger.error(" Error processing DataLedger diagnostics secret: " + e.message);
}


/********************************************
    10️⃣ FETCH HUB UI URL (Plain text)
********************************************/
try {
    var hubUiUrl = LookupHelper.get("Config", "HUB_UI_URL");


    if (!hubUiUrl || hubUiUrl.trim() === "") {
        throw "HUB UI URL retrieved from Lookup Manager is empty.";
    }
    hubUiUrl = hubUiUrl.trim();
    channelMap.put("HUB_UI_URL", hubUiUrl);
    globalMap.put("HUB_UI_URL", hubUiUrl);
    logger.info(" HUB UI URL loaded successfully from Lookup Manager: " + hubUiUrl);
} catch (e) {
    logger.error(" Error fetching HUB UI URL: " + e);
    setErrorResponse(500, "Failed to load HUB UI URL");
    throw e;
}


/*******************************
    Processing Agent Loader
********************************/


try {
	//value is either true or false
    var processingFeatureEnable = LookupHelper.get("Config", "ORG_TECHBD_PROCESSING_AGENT_FEATURE_ENABLED");

    channelMap.put("ORG_TECHBD_PROCESSING_AGENT_FEATURE_ENABLED", processingFeatureEnable);
    globalMap.put("ORG_TECHBD_PROCESSING_AGENT_FEATURE_ENABLED", processingFeatureEnable);

    logger.info(" Processing feature enable flag loaded into channelMap"+ processingFeatureEnable);

} catch (e) {
    logger.error("Error fetching processing feature enable flag from lookup manager: " + e.message);
}

try {
	//values will be comma seperated tenant ids eg:abc,xyz,test
    var processingAgentTenantIds = LookupHelper.get("Config", "ORG_TECHBD_PROCESSING_AGENT_TENANT_IDS");

    channelMap.put("ORG_TECHBD_PROCESSING_AGENT_TENANT_IDS", processingAgentTenantIds);
    globalMap.put("ORG_TECHBD_PROCESSING_AGENT_TENANT_IDS", processingAgentTenantIds);

    logger.info(" Processing agent tenant ids loaded into channelMap"+ processingAgentTenantIds);

} catch (e) {
    logger.error("Error fetching processing agent tenant ids from lookup manager: " + e.message);
}

try {
	//value is TXD
    var processingAgentValue = LookupHelper.get("Config", "ORG_TECHBD_PROCESSING_AGENT_VALUE");

    channelMap.put("ORG_TECHBD_PROCESSING_AGENT_VALUE", processingAgentValue);
    globalMap.put("ORG_TECHBD_PROCESSING_AGENT_VALUE", processingAgentValue);

    logger.info(" Processing agent value loaded into channelMap"+ processingAgentValue);

} catch (e) {
    logger.error("Error fetching processing agent value from lookup manager: " + e.message);
}



/********************************************
    DONE
********************************************/


/**
* Util function to generate json string wit hstatus and message
*/

function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

/**
* Util function to set error response.
*/
function setErrorResponse(statusCode, errorMessage) {
    responseMap.put('status', String(statusCode)); // Set HTTP status
    responseMap.put('message', errorMessage);
    responseMap.put('finalResponse', createJsonResponse(statusCode, errorMessage));
}

// Use logger.info with a single string (no channelMap arg)

var requestedPath = channelMap.get('requestedPath');

logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][: Request URL: " + requestedPath);

channelMap.put("requestUri", requestedPath);

if (requestedPath == "/") {
	return;
}

// =====================================================
// Header Extraction
// =====================================================

var startDate = $('headers').getHeader('X-TechBD-StartDate');
var endDate = $('headers').getHeader('X-TechBD-EndDate');
var tenantId = $('headers').getHeader('X-TechBD-Tenant-ID');

// =====================================================
// Required Header Validation
// =====================================================

if (startDate == null || startDate.trim() == "") {

	var errorMessage = "Missing required header: X-TechBD-StartDate";

	logger.info("[CHANNEL: " + channelName + "] " + errorMessage);

	setErrorResponse(400, errorMessage);

	throw errorMessage;
}

if (endDate == null || endDate.trim() == "") {

	var errorMessage = "Missing required header: X-TechBD-EndDate";

	logger.info("[CHANNEL: " + channelName + "] " + errorMessage);

	setErrorResponse(400, errorMessage);

	throw errorMessage;
}

// =====================================================
// Date Parsing Validation
// Mirrors parseFlexibleDate()
// =====================================================

function parseDate(dateStr, isStart) {

    var OffsetDateTime = Packages.java.time.OffsetDateTime;
    var LocalDate = Packages.java.time.LocalDate;
    var ZoneOffset = Packages.java.time.ZoneOffset;

    try {

        // ISO datetime
        if (dateStr.indexOf("T") > -1) {
            return OffsetDateTime.parse(dateStr);
        }

        // yyyy-MM-dd
        var localDate = LocalDate.parse(dateStr);

        if (isStart) {
            return localDate.atStartOfDay().atOffset(ZoneOffset.UTC);
        } else {
            return localDate.atTime(23, 59, 59).atOffset(ZoneOffset.UTC);
        }

    } catch (e) {

        throw "Invalid date-time format. Expected one of: yyyy-MM-dd or yyyy-MM-dd'T'HH:mm:ss.SSSXXX";
    }
}

var parsedStartDate;
var parsedEndDate;

try {

    parsedStartDate = parseDate(startDate, true);
    parsedEndDate = parseDate(endDate, false);

} catch (e) {

	var errorMessage = String(e);

	logger.info("[CHANNEL: " + channelName + "] " + errorMessage);

	setErrorResponse(400, errorMessage);

	throw errorMessage;
}

// =====================================================
// Date Range Validation
// Mirrors:
// if (endDate.isBefore(startDate))
// =====================================================

if (parsedEndDate.isBefore(parsedStartDate)) {

	var errorMessage = "endDate cannot be before startDate";

	logger.info("[CHANNEL: " + channelName + "] " + errorMessage);

	setErrorResponse(400, errorMessage);

	throw errorMessage;
}

// =====================================================
// Store Values
// =====================================================

channelMap.put('startDate', startDate);
channelMap.put('endDate', endDate);
channelMap.put('tenantId', tenantId);

var userAgent = channelMap.get('userAgent');

channelMap.put('userAgent', userAgent);

channelMap.put("endpoint", "submission");

logger.info("[CHANNEL: " + channelName + "] Replay validation successful");

com.mirth.connect.plugins.javascriptrule.script:
var httpMethod = String(sourceMap.get('method')).toUpperCase();
var contextPath = String(connectorMessage.getSourceMap().get('contextPath')).replace(/\/$/, '');

/**
 * Util function to generate JSON string
 */
function createJsonResponse(status, message) {
    return JSON.stringify({ status: status, message: message });
}

/**
 * Util function to set error response
 */
function setErrorResponse(statusCode, errorMessage) {
    responseMap.put('status', String(statusCode));
    responseMap.put('message', errorMessage);
    responseMap.put('finalResponse', createJsonResponse(statusCode, errorMessage));
}

/* =====================================
   1️⃣ ROOT ENDPOINT
===================================== */
if (contextPath === '') {

   if (httpMethod === 'GET') {

    responseMap.put('responseStatusCode', 200);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify({
        status: 200,
        message: "OK"
    }));

   return false;
}

    // Method not allowed for /
    return methodNotAllowed();
}

/* =====================================
   2️⃣ HEALTHCHECK

===================================== */
if (contextPath === '/healthcheck') {

    if (httpMethod === 'GET') {
         responseMap.put('responseStatusCode', 200);
	    responseMap.put('responseContentType', 'application/json');
	    responseMap.put('responseBody', JSON.stringify({
	        status: 200,
	        message: "OK"
	    }));

	   return false;
    }

    return methodNotAllowed();
}

/* =====================================
   3️ BUNDLE
===================================== */
if (contextPath === '/replay/' || contextPath === '/replay') {

    if (httpMethod === 'POST' || httpMethod === 'OPTIONS') {
        return true;
    }

    return methodNotAllowed();
}

/* =====================================
   ❌ INVALID PATH → 404
===================================== */
return notFound();




/* =====================================
   Helper Functions
===================================== */

function methodNotAllowed() {

    var errorResponse = "Method Not Allowed.";

    responseMap.put('responseStatusCode', 405);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(405, errorResponse);

    throw "Invalid method";
}

function notFound() {

    var errorResponse = "Not Found: Invalid endpoint.";

    responseMap.put('responseStatusCode', 404);
    responseMap.put('responseContentType', 'application/json');
    responseMap.put('responseBody', JSON.stringify(errorResponse));

    setErrorResponse(404, errorResponse);

    throw "Invalid endpoint";
}

properties.script:
logger.info("FHIR Replay Channel Started");

// ============================================================
// IMPORTS
// ============================================================

var DriverManager = java.sql.DriverManager;

var Instant = Packages.java.time.Instant;
var Duration = Packages.java.time.Duration;

var DefaultHttpClient =
    Packages.org.apache.http.impl.client.DefaultHttpClient;

var HttpPost =
    Packages.org.apache.http.client.methods.HttpPost;

var StringEntity =
    Packages.org.apache.http.entity.StringEntity;

var EntityUtils =
    Packages.org.apache.http.util.EntityUtils;


// ============================================================
// COMMON FUNCTIONS
// ============================================================

function getJdbcConnection() {

    var jdbcUrl = globalMap.get("jdbcUrl");

    var jdbcUsername =
        globalMap.get("JDBC_USERNAME");

    var jdbcPassword =
        globalMap.get("JDBC_PASSWORD");

    if (!jdbcUrl) {
        throw "jdbcUrl missing";
    }

    if (!jdbcUsername) {
        throw "JDBC_USERNAME missing";
    }

    if (!jdbcPassword) {
        throw "JDBC_PASSWORD missing";
    }

    return DriverManager.getConnection(
        jdbcUrl,
        jdbcUsername,
        jdbcPassword
    );
}


function truncateError(errorMessage) {

    if (errorMessage == null) {
        return "";
    }

    errorMessage = String(errorMessage);

    if (errorMessage.length > 4000) {
        return errorMessage.substring(0, 4000);
    }

    return errorMessage;
}


var PGobject = Packages.org.postgresql.util.PGobject;

function toJsonb(value) {
    var jsonbObj = new PGobject();
    jsonbObj.setType("jsonb");

	if (typeof value === "object") {
        value = JSON.stringify(value);
    }
    
    jsonbObj.setValue(value);
    logger.info("jsonbObj: " + jsonbObj);
    return jsonbObj;
}



// ============================================================
// SAVE FHIR PAYLOAD / INTERACTION STATE
// ============================================================

function saveFHIRPayload(
    interactionId,
    tenantId,
    requestUri,
    payloadJson,
    operation,
    source,
    groupInteractionId,
    masterInteractionId,
    replay
) {

    logger.info(
        "[CHANNEL: 1115 TECHBD " + channelName +
        "][INTERACTION ID: " + interactionId +
        " ]: replay: " + replay
    );

    logger.info(
        "[CHANNEL: 1115 TECHBD " + channelName +
        "][INTERACTION ID: " + interactionId +
        " ]: operation: " + operation
    );

    var conn = null;
    var stmt = null;

    try {

        // =====================================================
        // JDBC CONFIG
        // =====================================================

        var jdbcUrl = globalMap.get('jdbcUrl');

        if (jdbcUrl != null) {
            globalMap.put('jdbcUrl', jdbcUrl);
        } else {
            throw 'MC_JDBC_URL variable is not set';
        }

        var jdbcUsername =
            globalMap.get('JDBC_USERNAME');

        if (jdbcUsername != null) {
            globalMap.put(
                'jdbcUsername',
                jdbcUsername
            );
        } else {
            throw 'MC_JDBC_USERNAME variable is not set';
        }

        var jdbcPassword =
            globalMap.get('JDBC_PASSWORD');

        if (jdbcPassword != null) {
            globalMap.put(
                'jdbcPassword',
                jdbcPassword
            );
        } else {
            throw 'MC_JDBC_PASSWORD variable is not set';
        }

        // =====================================================
        // CONNECTION
        // =====================================================

        conn = DriverManager.getConnection(
            globalMap.get('jdbcUrl'),
            globalMap.get('jdbcUsername'),
            globalMap.get('jdbcPassword')
        );

        logger.info(
            "[CHANNEL: 1115 TECHBD " +
            channelName +
            "][INTERACTION ID: " +
            interactionId +
            " ]: Database connection established."
        );

        // =====================================================
        // SQL
        // =====================================================

        var sql =
            "select techbd_udi_ingress.register_interaction_fhir_request(" +
            "?::text, ?::text, ?::jsonb, ?::jsonb, ?::text, ?::text, ?::jsonb, " +
            "?::text, ?::text, ?::text, ?::text, ?::text, ?::text, ?::text, ?::text, ?::text, " +
            "?::timestamptz, ?::text, ?::boolean, ?::text, ?::text, ?::text, ?::text, ?::text, ?::jsonb, ?::text" +
            ")";

        stmt = conn.prepareCall(sql);

        // =====================================================
        // 1. p_interaction_id
        // =====================================================

        stmt.setString(1, interactionId);

        // =====================================================
        // 2. p_interaction_key
        // =====================================================

        stmt.setString(2, requestUri);

        // =====================================================
        // 3. p_nature
        // =====================================================

        var natureObj;

        if (operation === "saveForwardFHIRPayload") {

            if (replay === true) {

                natureObj = {
                    nature:
                        "Forwarded HTTP Request Replay",
                    tenant_id: tenantId
                };

            } else {

                natureObj = {
                    nature:
                        "Forward HTTP Request",
                    tenant_id: tenantId
                };
            }

        } else if (
            operation === "saveForwardFHIRSuccess"
        ) {

            if (replay === true) {

                natureObj = {
                    nature:
                        "Forwarded HTTP Response Replay",
                    tenant_id: tenantId
                };

            } else {

                natureObj = {
                    nature:
                        "Forwarded HTTP Response",
                    tenant_id: tenantId
                };
            }

        } else if (
            operation === "saveForwardFHIRFailure"
        ) {

            if (replay === true) {

                natureObj = {
                    nature:
                        "Forwarded HTTP Response Replay Error",
                    tenant_id: tenantId
                };

            } else {

                natureObj = {
                    nature:
                        "Forwarded HTTP Response Error",
                    tenant_id: tenantId
                };
            }

        } else {

            natureObj = {
                nature: operation || "UNKNOWN",
                tenant_id: tenantId
            };
        }

        stmt.setObject(
            3,
            toJsonb(JSON.stringify(natureObj)),
            java.sql.Types.OTHER
        );

        // =====================================================
        // 4. p_payload
        // =====================================================

        if (
            operation === "saveForwardFHIRPayload"
        ) {

            stmt.setObject(
                4,
                toJsonb(payloadJson),
                java.sql.Types.OTHER
            );

        } else {

            try {

                stmt.setObject(
                    4,
                    toJsonb(payloadJson),
                    java.sql.Types.OTHER
                );

            } catch (e) {

                stmt.setObject(
                    4,
                    toJsonb(
                        JSON.stringify({
                            error: String(payloadJson)
                        })
                    ),
                    java.sql.Types.OTHER
                );
            }
        }

        // =====================================================
        // 5. p_payload_text
        // =====================================================

        stmt.setNull(
            5,
            java.sql.Types.VARCHAR
        );

        // =====================================================
        // 6. p_rule_namespace
        // =====================================================

        stmt.setNull(
            6,
            java.sql.Types.VARCHAR
        );

        // =====================================================
        // 7. p_elaboration
        // =====================================================

        stmt.setNull(
            7,
            java.sql.Types.OTHER
        );

        // =====================================================
        // 8. p_content_type
        // =====================================================

        stmt.setString(
            8,
            "application/json"
        );

        // =====================================================
        // 9 & 10 STATE TRANSITIONS
        // =====================================================

        if (
            operation === "saveForwardFHIRPayload"
        ) {

            if (replay === true) {

                // SAME AS JAVA:
                // FAIL -> FORWARD
                stmt.setString(9, "FAIL");
                stmt.setString(10, "FORWARD");

            } else {

                stmt.setString(
                    9,
                    "DISPOSITION"
                );

                stmt.setString(
                    10,
                    "FORWARD"
                );
            }

        } else if (
            operation === "saveForwardFHIRSuccess"
        ) {

            stmt.setString(9, "FORWARD");
            stmt.setString(10, "COMPLETE");

        } else if (
            operation === "saveForwardFHIRFailure"
        ) {

            stmt.setString(9, "FORWARD");
            stmt.setString(10, "FAIL");

        } else {

            stmt.setNull(
                9,
                java.sql.Types.VARCHAR
            );

            stmt.setNull(
                10,
                java.sql.Types.VARCHAR
            );
        }

        // =====================================================
        // 11. p_state_transition_reason
        // =====================================================

        stmt.setNull(
            11,
            java.sql.Types.VARCHAR
        );

        // =====================================================
        // 12-16 USER FIELDS
        // =====================================================

        stmt.setNull(12, java.sql.Types.VARCHAR);
        stmt.setNull(13, java.sql.Types.VARCHAR);
        stmt.setNull(14, java.sql.Types.VARCHAR);
        stmt.setNull(15, java.sql.Types.VARCHAR);
        stmt.setNull(16, java.sql.Types.VARCHAR);

        // =====================================================
        // 17. p_created_at
        // =====================================================

        stmt.setObject(
            17,
            java.time.OffsetDateTime.now()
        );

        // =====================================================
        // 18. p_provenance
        // =====================================================

        var provenanceString =
            "channel:" +
            channelName +
            ", script:deploy";

        stmt.setString(
            18,
            provenanceString
        );

        // =====================================================
        // 19. p_hub_upsert_behavior
        // =====================================================

        stmt.setNull(
            19,
            java.sql.Types.BOOLEAN
        );

        // =====================================================
        // 20. p_source_hub_interaction_id
        // =====================================================

        stmt.setString(
            20,
            masterInteractionId
        );

        // =====================================================
        // 21. p_origin
        // =====================================================

        stmt.setNull(
            21,
            java.sql.Types.VARCHAR
        );

        // =====================================================
        // 22. p_source_type
        // =====================================================

        stmt.setString(
            22,
            source
        );

        // =====================================================
        // 23. p_group_hub_interaction_id
        // =====================================================

        var normalizedSource =
            source
                ? String(source)
                    .trim()
                    .toUpperCase()
                : null;

        if (normalizedSource === "CSV") {

            stmt.setString(
                23,
                groupInteractionId
            );

        } else {

            stmt.setNull(
                23,
                java.sql.Types.VARCHAR
            );
        }

        // =====================================================
        // 24. p_request_source
        // =====================================================

        stmt.setNull(
            24,
            java.sql.Types.VARCHAR
        );

        // =====================================================
        // 25. p_additional_details
        // =====================================================

        if (
            operation === "saveForwardFHIRSuccess"
            || operation ===
            "saveForwardFHIRFailure"
        ) {

            var finishIso =
                java.time.Instant.now()
                .toString();

            var additionalDetailsObj = {
                request: {
                    "X-Observability-Metric-Interaction-Finish-Time":
                        finishIso
                }
            };

            stmt.setObject(
                25,
                toJsonb(
                    JSON.stringify(
                        additionalDetailsObj
                    )
                ),
                java.sql.Types.OTHER
            );

        } else {

            stmt.setNull(
                25,
                java.sql.Types.OTHER
            );
        }

        // =====================================================
        // 26. p_techbd_version_number
        // =====================================================

        stmt.setNull(
            26,
            java.sql.Types.VARCHAR
        );

        // =====================================================
        // EXECUTE
        // =====================================================

        stmt.execute();

        logger.info(
            "[CHANNEL: 1115 TECHBD " +
            channelName +
            "][INTERACTION ID: " +
            interactionId +
            " ]: Stored procedure executed successfully."
        );

    } catch (e) {

        logger.error(
            "[CHANNEL: 1115 TECHBD " +
            channelName +
            "][INTERACTION ID: " +
            interactionId +
            " ]: Error executing stored procedure: "
            + e
        );

        throw e;

    } finally {

        if (stmt != null) {
            stmt.close();
        }

        if (conn != null) {
            conn.close();
        }

        logger.info(
            "[CHANNEL: 1115 TECHBD " +
            channelName +
            "][INTERACTION ID: " +
            interactionId +
            " ]: DB connection closed."
        );
    }
}


// ============================================================
// GET BUNDLES TO REPLAY
// ============================================================

function getBundlesToReplay(
    replayId,
    startDate,
    endDate,
    tenantId
) {

    var conn = null;
    var stmt = null;
    var rs = null;

    var bundleList = [];

    try {

        conn = getJdbcConnection();

        logger.info("Connected To DB");

        var sql =
            "select * from techbd_udi_ingress.get_fhir_bundles_to_replay(" +
            "?::text," +
            "?::timestamptz," +
            "?::timestamptz," +
            "?::text" +
            ")";

        stmt = conn.prepareCall(sql);

        stmt.setString(1, replayId);
        stmt.setObject(2, startDate);
        stmt.setObject(3, endDate);
        stmt.setString(4, tenantId);

        rs = stmt.executeQuery();

        while (rs.next()) {

            var jsonText = rs.getString(1);

            logger.info("Replay Query Result: " + jsonText);

            var parsed = JSON.parse(String(jsonText));

            if (parsed.bundles != null) {

                for each (var item in parsed.bundles) {
                    bundleList.push(item);
                }
            }
        }

    } catch (e) {

        logger.error(
            "Error Fetching Replay Bundles: " + e
        );

        throw e;

    } finally {

        if (rs != null) rs.close();
        if (stmt != null) stmt.close();
        if (conn != null) conn.close();
    }

    return bundleList;
}


// ============================================================
// GET ORIGINAL PAYLOAD
// ============================================================

function getNyecPayload(interactionId) {

    var conn = null;
    var stmt = null;
    var rs = null;

    try {

        conn = getJdbcConnection();

        var sql =
            "select techbd_udi_ingress.get_fhir_payload_for_nyec(?::text)";

        stmt = conn.prepareCall(sql);

        stmt.setString(1, interactionId);

        rs = stmt.executeQuery();

        if (rs.next()) {

            return rs.getString(1);
        }

        return null;

    } catch (e) {

        logger.error(
            "Error Fetching Payload: " + e
        );

        throw e;

    } finally {

        if (rs != null) rs.close();
        if (stmt != null) stmt.close();
        if (conn != null) conn.close();
    }
}


function resolveProcessingAgent(tenantId) {

    var featureEnabled =
        String(
            globalMap.get(
                "ORG_TECHBD_PROCESSING_AGENT_FEATURE_ENABLED"
            )
        );

    var tenantIds =
        String(
            globalMap.get(
                "ORG_TECHBD_PROCESSING_AGENT_TENANT_IDS"
            )
        );

    var value =
        String(
            globalMap.get(
                "ORG_TECHBD_PROCESSING_AGENT_VALUE"
            )
        );

    tenantId = String(tenantId);

    if (
        !tenantId
        || featureEnabled !== "true"
    ) {

        return tenantId;
    }

    var incomingTenant =
        tenantId.trim().toLowerCase();

    var tenantList =
        tenantIds.split(",");

    for (var i = 0; i < tenantList.length; i++) {

        var configTenant =
            String(tenantList[i])
                .trim()
                .toLowerCase();

        if (configTenant === incomingTenant) {

            return value;
        }
    }

    return tenantId;
}


// ============================================================
// SEND TO DATALAKE
// ============================================================

function sendToDataLake(
    payload,
    tenantId
) {

    var datalakeApiUrl =
        channelMap.get("DATALAKE_API_URL");

    if (!datalakeApiUrl) {

        datalakeApiUrl =
            globalMap.get("datalakeApiUrl");
    }

    var apiKey =
        channelMap.get("DATA_LAKE_API_KEY");

    if (!apiKey) {

        apiKey =
            globalMap.get("DATA_LAKE_API_KEY");
    }

    if (!datalakeApiUrl) {
        throw "DATALAKE_API_URL missing";
    }

    if (!tenantId) {
        throw "Tenant ID missing";
    }

    if (!apiKey) {
        throw "DATA_LAKE_API_KEY missing";
    }

    // =====================================================
    // PROCESSING AGENT
    // =====================================================

    var processingAgent =
        resolveProcessingAgent(tenantId);

    var finalUrl =
        datalakeApiUrl
        + "?processingAgent="
        + processingAgent;

    logger.info(
        "Calling DataLake URL: "
        + finalUrl
    );

    // =====================================================
    // HTTP CLIENT
    // =====================================================

    var client =
        new DefaultHttpClient();

    var post =
        new HttpPost(finalUrl);

    // =====================================================
    // HEADERS
    // =====================================================

    post.setHeader(
        "X-TechBD-Tenant-ID",
        tenantId
    );

    post.setHeader(
        "Content-Type",
        "application/fhir+json"
    );

    post.setHeader(
        "x-api-key",
        apiKey
    );

    // =====================================================
    // PAYLOAD
    // =====================================================

    post.setEntity(
        new StringEntity(
            payload,
            "UTF-8"
        )
    );

    var statusCode = 500;

    var responseBody = "";

    var statusText = "";

    try {

        var response =
            client.execute(post);

        var statusLine =
            response.getStatusLine();

        statusCode =
            statusLine.getStatusCode();

        statusText =
            statusLine.getReasonPhrase();

        if (
            response.getEntity() != null
        ) {

            responseBody =
                EntityUtils.toString(
                    response.getEntity(),
                    "UTF-8"
                );
        }

    } catch (e) {

        logger.error(
            "DataLake Call Failed: "
            + e
        );

        var errMsg = "";

        if (e.javaException) {

            errMsg =
                e.javaException.getMessage();

        } else if (e.message) {

            errMsg =
                e.message;

        } else {

            errMsg =
                String(e);
        }

        if (
            e.javaException
            && e.javaException instanceof
            java.net.UnknownHostException
        ) {

            var host =
                String(datalakeApiUrl)
                .replace(/^https?:\/\//, '')
                .split("/")[0];

            errMsg =
                "Failed to resolve '"
                + host + "'";
        }

        throw errMsg;
    }

    return {
        statusCode: statusCode,
        statusText: statusText,
        responseBody: responseBody
    };
}


// ============================================================
// UPDATE REPLAY STATUS
// ============================================================

function updateReplayStatus(
    interactionId,
    replayId,
    bundleId,
    status,
    errorMessage
) {

    var conn = null;
    var stmt = null;
    var rs = null;

    try {

        conn = getJdbcConnection();

        var sql =
            "select techbd_udi_ingress.update_fhir_replay_status(" +
            "?::text," +
            "?::text," +
            "?::text," +
            "?::jsonb," +
            "?::text," +
            "?::text" +
            ")";

        stmt = conn.prepareStatement(sql);

        stmt.setString(1, interactionId);
        stmt.setString(2, status);
        stmt.setString(
            3,
            truncateError(errorMessage)
        );
        stmt.setNull(
            4,
            java.sql.Types.OTHER
        );
        stmt.setString(5, bundleId);
        stmt.setString(6, replayId);

        rs = stmt.executeQuery();

        if (rs.next()) {

            logger.info(
                "Replay Status Response: "
                + rs.getString(1)
            );
        }

        logger.info(
            "FHIR Replay Status Updated Successfully"
        );

    } catch (e) {

        logger.error(
            "Failed Updating Replay Status: " + e
        );

    } finally {

        if (rs != null) rs.close();
        if (stmt != null) stmt.close();
        if (conn != null) conn.close();
    }
}


// ============================================================
// MAIN REPLAY LOGIC
// ============================================================


var uuid = generateUuid();
logger.info("Generated UUID v7: " + uuid);

var replayId =
    uuid
    .toString();

var startDate =
    channelMap.get("startDate");

var endDate =
    channelMap.get("endDate");

var tenantId =
    channelMap.get("tenantId");

var bundles =
    getBundlesToReplay(
        replayId,
        startDate,
        endDate,
        tenantId
    );

var bundleCount =
    bundles != null
    ? bundles.length
    : 0;

if (bundleCount == 0) {

    var emptyResponse = {
        replay_id: replayId,
        total_bundles: 0,
        message:
            "No bundles to replay during this period."
    };

    logger.info(
        "Replay Result: "
        + JSON.stringify(emptyResponse)
    );

    responseMap.put(
        "finalResponse",
        JSON.stringify(emptyResponse)
    );

} else {

    var Runnable =
        java.lang.Runnable;

    var Thread =
        java.lang.Thread;

    var replayTask =
        new Runnable({

        run: function() {

            try {

                logger.info(
                    "FHIR Replay Background Processing Started"
                );

                for each (var bundle in bundles) {

                    var bundleId =
                        bundle.bundleid;

                    var interactionId =
                        bundle.interactionid;

                    var groupInteractionId =
                        bundle.groupInteractionId;

                    var masterInteractionId =
                        bundle.zipInteractionID;

                    var replayTenantId =
                        bundle.tenantID;

                    var requestUri =
                        bundle.uri;

                    var source =
                        bundle.source;

                    var status = "Success";

                    var errorMessage = "";

                    try {

                        logger.info(
                            "Processing Bundle ID: "
                            + bundleId
                        );

                        var payload =
                            getNyecPayload(
                                interactionId
                            );

                        if (
                            !payload
                            || payload == ""
                        ) {

                            throw "Payload empty";
                        }

                        saveFHIRPayload(
                            interactionId,
                            replayTenantId,
                            requestUri,
                            payload,
                            "saveForwardFHIRPayload",
                            source,
                            groupInteractionId,
                            masterInteractionId,
                            true
                        );

                        var start =
                            Instant.now();

                        var response =
                            sendToDataLake(
                                payload,
                                replayTenantId
                            );

                        var end =
                            Instant.now();

                        logger.info(
                            "Replay API Time Taken: "
                            + Duration
                                .between(start, end)
                                .toMillis()
                            + " ms"
                        );

                        logger.info(
                            "Replay Status Code: "
                            + response.statusCode
                        );

                        var parsedResponse = null;

                        try {

                            parsedResponse =
                                JSON.parse(
                                    response.responseBody
                                );

                        } catch (e) {

                            parsedResponse = {
                                status: "failure",
                                error: "Invalid JSON",
                                message:
                                    response.responseBody
                            };
                        }

                        var dlStatus =
                            String(
                                parsedResponse.status || ""
                            ).toLowerCase();

                        if (
                            response.statusCode >= 200
                            && response.statusCode < 300
                            && dlStatus == "success"
                        ) {

                            status = "Success";

                            saveFHIRPayload(
                                interactionId,
                                replayTenantId,
                                requestUri,
                                JSON.stringify(parsedResponse),
                                "saveForwardFHIRSuccess",
                                source,
                                groupInteractionId,
                                masterInteractionId,
                                true
                            );

                        } else {

                            status = "Failed";

                            errorMessage =
                                JSON.stringify(parsedResponse);

                            saveFHIRPayload(
                                interactionId,
                                replayTenantId,
                                requestUri,
                                JSON.stringify(parsedResponse),
                                "saveForwardFHIRFailure",
                                source,
                                groupInteractionId,
                                masterInteractionId,
                                true
                            );
                        }

                    } catch (e) {

                        status = "Failed";

                        if (e.javaException) {

                            errorMessage =
                                e.javaException.getMessage();

                        } else if (e.message) {

                            errorMessage =
                                e.message;

                        } else {

                            errorMessage =
                                String(e);
                        }

                        logger.error(
                            "Replay Failed: "
                            + errorMessage
                        );

                        try {

                            saveFHIRPayload(
                                interactionId,
                                replayTenantId,
                                requestUri,
                                truncateError(errorMessage),
                                "saveForwardFHIRFailure",
                                source,
                                groupInteractionId,
                                masterInteractionId,
                                true
                            );

                        } catch (innerEx) {

                            logger.error(
                                "Failure save failed: "
                                + innerEx
                            );
                        }

                    } finally {

                        updateReplayStatus(
                            interactionId,
                            replayId,
                            bundleId,
                            status,
                            errorMessage
                        );
                    }
                }

                logger.info(
                    "FHIR Replay Background Processing Completed"
                );

            } catch (threadError) {

                logger.error(
                    "Replay Background Thread Failed: "
                    + threadError
                );
            }
        }
    });

    var replayThread =
        new Thread(replayTask);

    replayThread.start();

    var immediateResponse = {
        replay_id: replayId,
        total_bundles: bundleCount,
        message:
            "Replay started. Please refer to the Hub UI Interactions > FHIR Data tab for detailed status updates."
    };

    logger.info(
        "Replay Started Async: "
        + JSON.stringify(immediateResponse)
    );

    responseMap.put(
        "finalResponse",
        JSON.stringify(immediateResponse)
    );
}

