function sendDataLedgerSync(payload,interactionId) {
    logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]:  sendDataLedgerSync: " + payload);
    
    var apiUrl = globalMap.get("DATA_LEDGER_API_URL");
    var dataLedgerApiKey = globalMap.get("TECHBD_NYEC_DATALEDGER_API_KEY");

    logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]: API URL: ####### " + apiUrl);
     logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]: DATA_LEDGER_API_URL####### " + globalMap.get("DATA_LEDGER_API_URL"));
      //logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]:  TECHBD_NYEC_DATALEDGER_API_KEY ####### " + globalMap.get("TECHBD_NYEC_DATALEDGER_API_KEY"));

    if (apiUrl == null) {
        throw new Error("Environment variable DATA_LEDGER_API_URL is not set.");
    }
    if (dataLedgerApiKey == null) {
        throw new Error("Environment variable 'TECHBD_NYEC_DATALEDGER_API_KEY' is not set.");
    }

    try {
        var HttpClients = org.apache.http.impl.client.HttpClients;
        var HttpPost = org.apache.http.client.methods.HttpPost;
        var StringEntity = org.apache.http.entity.StringEntity;
        var EntityUtils = org.apache.http.util.EntityUtils;

        var httpClient = HttpClients.createDefault();
        var httpPost = new HttpPost(apiUrl);

        httpPost.setHeader("Content-Type", "application/json");
        httpPost.setHeader("Accept", "application/json");
       
        if (dataLedgerApiKey != null) {
        	httpPost.setHeader("x-api-key", dataLedgerApiKey); // ✅ Add x-api-key header
        }

        var entity = new StringEntity(payload, "UTF-8");
        httpPost.setEntity(entity);

        
        try {
        	var response = httpClient.execute(httpPost);
            var statusCode = response.getStatusLine().getStatusCode();
            logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]: sendDataLedgerSync response status: " + statusCode);
            var responseBody = EntityUtils.toString(response.getEntity());

            if (statusCode >= 200 && statusCode < 300) {
                logger.info("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]: Data Ledger API Response: " + responseBody);
                return {
                    statusCode: statusCode,
                    body: responseBody
                };
            } else {
                logger.error("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]: Data Ledger API Error. Status: " + statusCode + ", Response: " + responseBody);
                throw new Error("Request failed with status " + statusCode);
            }
        } finally {
            EntityUtils.consumeQuietly(response.getEntity());
             httpClient.close();
        }
    } catch (error) {
        logger.error("[CHANNEL: 1115 TECHBD " + channelName + "][INTERACTION ID: " +interactionId +" ]: Data Ledger API Request Failed: " + error.message);
        throw error;
    }
}

globalMap.put('sendDataLedgerSync', sendDataLedgerSync);

// Function to extract a query param from the URI
function getQueryParam(uriString, paramName) {
    if (!uriString) return null;
    var regex = new RegExp('[?&]' + paramName + '=([^&]*)', 'i');
    var match = uriString.match(regex);
    return (match && match[1]) ? decodeURIComponent(match[1]) : null;
}
globalMap.put('getQueryParam', getQueryParam);

